227	  const phoneRef = useRef<HTMLDivElement>(null);
228	  const isCtaFloating = useFloatingCta(phoneRef);
229	
230	  return (
231	    <section className="relative flex w-full flex-col items-center px-4 py-20 sm:px-6 sm:py-24 lg:px-8">
