241	        <div ref={phoneRef}>
242	          <PhoneFrame platform={active} messages={visibleMessages} />
243	        </div>
244	
245	        <FloatingCTA
246	          isFloating={isCtaFloating}
247	          action={active.primaryAction}
248	          actionKey={active.id}
249	          iconSrc={active.icon}
