256	function FloatingCTA({
257	  isFloating,
258	  action,
259	  actionKey,
260	  iconSrc,
261	}: {
262	  isFloating: boolean;
263	  action: ActionLink;
264	  actionKey: string;
265	  iconSrc: string;
266	}) {
267	  // Reserve the static-flow slot so the layout never jumps when the button
268	  // pops out of the flow into a fixed position. The CTA is rendered twice:
269	  //   - In flow, invisible while floating (reserves space)
270	  //   - Fixed at the bottom while floating, fades in via opacity only
271	  return (
272	    <div className="relative flex w-full justify-center pt-2">
273	      <div
274	        aria-hidden={isFloating}
275	        className={isFloating ? "pointer-events-none opacity-0" : "opacity-100"}
276	      >
277	        <PlatformCTASwitcher
278	          actionKey={actionKey}
279	          action={action}
280	          iconSrc={iconSrc}
281	        />
282	      </div>
283	
284	      <AnimatePresence initial={false}>
285	        {isFloating && (
286	          <m.div
287	            key="floating"
288	            initial={{ opacity: 0 }}
289	            animate={{ opacity: 1 }}
290	            exit={{ opacity: 0 }}
291	            transition={{ duration: 0.18, ease: "easeOut" }}
292	            className="pointer-events-none fixed inset-x-0 bottom-6 z-[1001] flex justify-center px-4"
293	          >
294	            <div className="pointer-events-auto">
295	              <PlatformCTASwitcher
296	                actionKey={actionKey}
297	                action={action}
298	                iconSrc={iconSrc}
299	              />
300	            </div>
301	          </m.div>
302	        )}
303	      </AnimatePresence>
304	    </div>
305	  );
306	}
307	
308	function PlatformCTASwitcher({
309	  actionKey,
310	  action,
311	  iconSrc,
312	}: {
313	  actionKey: string;
314	  action: ActionLink;
315	  iconSrc: string;
316	}) {
317	  return (
318	    <AnimatePresence mode="wait" initial={false}>
319	      <m.div
320	        key={actionKey}
321	        initial={{ opacity: 0, y: 4 }}
322	        animate={{ opacity: 1, y: 0 }}
323	        exit={{ opacity: 0, y: -4 }}
324	        transition={{ duration: 0.18, ease: "easeOut" }}
325	      >
326	        <PrimaryCTA action={action} iconSrc={iconSrc} />
327	      </m.div>
328	    </AnimatePresence>
329	  );
330	}
331	
332	function useFloatingCta(
333	  phoneRef: React.RefObject<HTMLDivElement | null>,
334	): boolean {
335	  const [floating, setFloating] = useState(false);
336	
337	  useEffect(() => {
338	    const phone = phoneRef.current;
339	    if (!phone) return;
340	
341	    const update = (): void => {
342	      const phoneRect = phone.getBoundingClientRect();
343	      const vh = window.innerHeight;
344	      // Threshold is tuned so the floating button and its static-flow slot
345	      // line up vertically at the moment of switch — the visual position
346	      // doesn't jump.
347	      const phoneEnoughVisible = phoneRect.top < vh - 200;
348	      // The floating button sits at vh - 56 (bottom-6 + button height). The
349	      // static slot sits at phoneRect.bottom + 62 (flex gap-8 + pt-2 + half
350	      // button). The switch happens when the two y positions match.
351	      const phoneStillNearBottom = phoneRect.bottom > vh - 118;
352	      setFloating(phoneEnoughVisible && phoneStillNearBottom);
353	    };
354	
355	    update();
356	    window.addEventListener("scroll", update, { passive: true });
357	    window.addEventListener("resize", update);
358	    return () => {
359	      window.removeEventListener("scroll", update);
360	      window.removeEventListener("resize", update);
361	    };
362	  }, [phoneRef]);
363	
364	  return floating;
365	}
366	
367	const TYPING_DELAY_MS = 450;
368	const TYPING_DURATION_MS = 850;
369	
370	function useStaggeredMessages(platform: Platform): ChatMessageItem[] {
371	  const allMessages = platform.demo.messages;
372	  const [visibleCount, setVisibleCount] = useState(1);
373	  const [showTyping, setShowTyping] = useState(false);
374	
375	  useEffect(() => {
376	    setVisibleCount(1);
377	    setShowTyping(false);
378	    if (allMessages.length <= 1) return;
379	
380	    const timers: ReturnType<typeof setTimeout>[] = [];
381	    let elapsed = 0;
382	    for (let i = 1; i < allMessages.length; i++) {
383	      elapsed += TYPING_DELAY_MS;
384	      timers.push(setTimeout(() => setShowTyping(true), elapsed));
385	      elapsed += TYPING_DURATION_MS;
386	      timers.push(
387	        setTimeout(() => {
388	          setShowTyping(false);
389	          setVisibleCount((c) => c + 1);
390	        }, elapsed),
391	      );
392	    }
393	
394	    return () => {
395	      for (const t of timers) clearTimeout(t);
396	    };
397	  }, [allMessages]);
398	
399	  return useMemo(() => {
400	    const real = allMessages.slice(0, visibleCount).map((m, i) => ({
401	      ...m,
402	      id: m.id ?? `msg-${i}`,
403	    }));
404	    if (!showTyping || visibleCount >= allMessages.length) return real;
405	    const next = allMessages[visibleCount];
406	    return [
407	      ...real,
408	      {
409	        id: `typing-${visibleCount}`,
410	        from: next.from,
411	        author: next.author,
412	        avatar: next.avatar,
413	        authorColor: next.authorColor,
414	        typing: true,
415	      },
416	    ];
417	  }, [allMessages, visibleCount, showTyping]);
418	}
419	
420	function PlatformChips({
421	  platforms,
422	  activeId,
423	  onSelect,
424	}: {
425	  platforms: Platform[];
426	  activeId: ChatPlatform;
427	  onSelect: (id: ChatPlatform) => void;
428	}) {
429	  return (
430	    <div
431	      role="tablist"
432	      aria-label="Choose a platform"
433	      className="flex flex-wrap items-center justify-center gap-2"
434	    >
435	      {platforms.map((p) => {
436	        const isActive = p.id === activeId;
437	        return (
438	          <Chip
439	            key={p.id}
440	            variant={isActive ? "solid" : "flat"}
441	            color={isActive ? "primary" : "default"}
442	            size="lg"
443	            role="tab"
444	            aria-selected={isActive}
445	            onClick={() => onSelect(p.id)}
446	            className="cursor-pointer select-none"
447	            startContent={
448	              <Image
449	                src={p.icon}
450	                alt=""
451	                width={20}
452	                height={20}
453	                className="h-5 w-5 shrink-0 rounded"
454	                aria-hidden
455	              />
456	            }
457	          >
458	            {p.name}
459	          </Chip>
460	        );
461	      })}
462	    </div>
463	  );
464	}
465	
466	function PhoneFrame({
467	  platform,
468	  messages,
469	}: {
470	  platform: Platform;
471	  messages: ChatMessageItem[];
472	}) {
473	  return (
474	    <div className="relative isolate">
475	      <div
476	        aria-hidden
477	        className="-z-10 pointer-events-none absolute -inset-x-[28rem] -inset-y-[20rem]"
478	        style={{
479	          backgroundImage:
480	            "radial-gradient(closest-side, rgba(0,187,255,0.7), rgba(0,187,255,0.25) 35%, rgba(0,187,255,0.06) 65%, transparent 80%)",
481	          filter: "blur(18px)",
482	        }}
483	      />
484	      <IPhoneMockup
485	        screenBackground={platform.phone.screenBackground}
486	        statusBarTone={platform.phone.statusBarTone}
487	      >
488	        <AnimatePresence mode="wait" initial={false}>
489	          <m.div
490	            key={platform.id}
491	            className="flex h-full flex-col"
492	            initial={{ opacity: 0, y: 8 }}
493	            animate={{ opacity: 1, y: 0 }}
494	            exit={{ opacity: 0, y: -8 }}
495	            transition={{ duration: 0.2, ease: "easeOut" }}
496	          >
497	            <ChatDemo
498	              platform={platform.id}
499	              title={platform.demo.title}
500	              subtitle={platform.demo.subtitle}
501	              messages={messages}
502	            />
503	          </m.div>
504	        </AnimatePresence>
505	      </IPhoneMockup>
506	    </div>
507	  );
508	}
509	
510	function PrimaryCTA({
511	  action,
512	  iconSrc,
513	}: {
514	  action: ActionLink;
515	  iconSrc: string;
516	}) {
517	  const button = (
518	    <RaisedButton
519	      color="#00bbff"
520	      className="text-black! h-10 rounded-full pr-4 pl-1.5 before:rounded-full"
521	    >
522	      <span className="flex items-center gap-2">
523	        <Image
524	          src={iconSrc}
525	          alt=""
526	          width={28}
527	          height={28}
528	          aria-hidden
529	          className="h-7 w-7 shrink-0 rounded"
530	        />
531	        {action.label}
532	        <CircleArrowRight02Icon size={18} />
533	      </span>
534	    </RaisedButton>
535	  );
536	
537	  if (action.external) {
538	    return (
539	      <a href={action.href} target="_blank" rel="noreferrer">
540	        {button}
541	      </a>
542	    );
543	  }
544	
545	  return <Link href={action.href}>{button}</Link>;
546	}
