      {/* Header — iOS chrome from WhatsApp Chat.svg (#F6F6F6) */}
      <div className="flex shrink-0 flex-col" style={{ background: chromeBg }}>
        <div
          className="grid items-center"
          style={{
            gridTemplateColumns: "1fr auto 1fr",
            padding: "6px 12px 8px",
            gap: 8,
          }}
        >
          <div className="flex items-center" style={{ color: accent }}>
            <svg
              width="12"
              height="20"
              viewBox="0 0 12 20"
              aria-hidden
              fill="none"
            >
              <path
                d="M10 2 2 10l8 8"
                stroke={accent}
                strokeWidth="2.4"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </div>
          <div className="flex flex-col items-center" style={{ minWidth: 0 }}>
            <div
              className="overflow-hidden rounded-full"
              style={{ width: 32, height: 32 }}
            >
              {/* biome-ignore lint/performance/noImgElement: avatar */}
              <img
                src={headerAvatar}
                alt=""
                style={{ width: 32, height: 32, objectFit: "cover" }}
              />
            </div>
            <span
              style={{
                fontSize: 10,
                marginTop: 2,
                color: textColor,
                letterSpacing: "-0.01em",
                maxWidth: 140,
                overflow: "hidden",
                textOverflow: "ellipsis",
                whiteSpace: "nowrap",
              }}
            >
              {title ?? "GAIA"}
            </span>
          </div>
          <div
            className="flex items-center justify-end"
            style={{ color: accent }}
          >
            <svg
              width="22"
              height="14"
              viewBox="0 0 22 14"
              aria-hidden
              fill="none"
            >
              <rect
                x="0.5"
                y="0.5"
                width="15"
                height="13"
                rx="3"
                stroke={accent}
              />
              <path
                d="M16 4l5 -3v12l-5 -3z"
                fill={accent}
                stroke={accent}
                strokeWidth="0.5"
                strokeLinejoin="round"
              />
            </svg>
          </div>
        </div>
        <div style={{ height: 0.5, background: "rgba(60,60,67,0.18)" }} />
      </div>

      {/* Chat area — light gray with the WhatsApp doodle pattern */}
      <div
        className="flex flex-1 flex-col overflow-y-auto px-3 pb-3"
        style={{
          scrollbarWidth: "none",
          gap: 8,
          backgroundColor: bg,
          backgroundImage: 'url("/whatsapp-doodle.png")',
          backgroundRepeat: "repeat",
          backgroundSize: "404px auto",
          paddingTop: 8,
        }}
      >
        {grouped.map((group, gi) => {
          const isMe = group.from === "me";
          return (
            <div
              key={gi}
              className={cn(
                "flex flex-col",
                isMe ? "items-end" : "items-start",
              )}
              style={{ gap: 2 }}
            >
